const { execSync } = require('child_process');


const minifluxUrl = $env.MINIFLUX_URL || 'http://localhost:8070';
const minifluxApiKey = $env.MINIFLUX_API_KEY || '';

let recentEntries = [];
if (minifluxApiKey) {
  try {
    const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
    const result = execSync(`curl -s -H "X-Auth-Token: ${minifluxApiKey}" "${minifluxUrl}/v1/entries?limit=50&order=published_at&direction=desc&status=unread&after=${encodeURIComponent(weekAgo)}"`, {
      encoding: 'utf-8', timeout: 15000
    });
    const data = JSON.parse(result);
    if (data.entries) recentEntries = data.entries.map(e => ({ title: e.title, url: e.url, feed: e.feed ? e.feed.title : '', published: e.published_at }));
  } catch(e) {}
}

let recentRuns = [];
try {
  const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
  const sql = `SELECT query, mode, quality_score, verdict, source_count, started_at FROM research_run WHERE started_at > '${weekAgo}' AND status = 'completed' ORDER BY started_at DESC LIMIT 20;`;
  const result = execSync(`curl -s -X POST -H "surreal-ns: research" -H "surreal-db: workflow" -H "Content-Type: application/json" -H "Accept: application/json" -u "${$env.SURREAL_USER || 'root'}:${$env.SURREAL_PASS || 'root'}" -d '${sql}' "http://127.0.0.1:18000/sql"`, {
    encoding: 'utf-8', timeout: 10000
  });
  const data = JSON.parse(result);
  if (data[0] && data[0].result) recentRuns = data[0].result;
} catch(e) {}

return [{ json: { rss_entries: recentEntries, recent_runs: recentRuns, entry_count: recentEntries.length, run_count: recentRuns.length } }];

const { execSync } = require('child_process');
const fs = require('fs');

const data = $input.first().json;


const cliEnv = { HOME: '/home/clawd', PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin', GEMINI_API_KEY: $env.GEMINI_API_KEY || $env.GOOGLE_GEMINI_API_KEY || '' };

let context = `Weekly Digest Context:\n\nRSS Entries (${data.entry_count}):\n`;
for (const entry of (data.rss_entries || []).slice(0, 20)) {
  context += `- ${entry.title} (${entry.feed}) — ${entry.url}\n`;
}

context += `\nRecent Research Runs (${data.run_count}):\n`;
for (const run of (data.recent_runs || []).slice(0, 10)) {
  context += `- ${run.query} (${run.mode}, Score: ${run.quality_score}, Verdict: ${run.verdict || 'N/A'})\n`;
}

const prompt = `Du bist ein Weekly Digest Writer. Erstelle eine Zusammenfassung der wichtigsten Entwicklungen der Woche basierend auf diesen Daten.\n\n${context}\n\nFormat:\n# Weekly Digest - [Datum]\n## Top Stories\n[3-5 wichtigste Nachrichten]\n## Research Highlights\n[Zusammenfassung der Research-Runs]\n## Trending Topics\n[Erkannte Trends]\n## Quellen\n[Nummerierte Liste]`;

const tmpFile = '/tmp/digest_' + Date.now() + '.txt';
fs.writeFileSync(tmpFile, prompt);

let digest = '';
try {
  digest = execSync(`cat "${tmpFile}" | gemini -p "Generate the weekly digest in German."`, {
    encoding: 'utf-8', timeout: 120000, env: cliEnv, maxBuffer: 5 * 1024 * 1024
  });
} catch (err) {
  digest = `# Weekly Digest\n\nFehler bei der Erstellung: ${err.message || 'Timeout'}\n\n## RSS Entries: ${data.entry_count}\n## Research Runs: ${data.run_count}`;
}

try { fs.unlinkSync(tmpFile); } catch(e) {}

return [{ json: { digest: digest.trim(), entry_count: data.entry_count, run_count: data.run_count } }];

const { execSync } = require('child_process');


const data = $input.first().json;
let message = `\ud83d\udcf0 Weekly Research Digest\n\n${data.digest || 'Kein Digest generiert.'}\n\nRSS: ${data.entry_count} entries | Runs: ${data.run_count} completed`;

if (message.length > 4096) message = message.substring(0, 4090) + '\n(...)';

message = message.replace(/```[\s\S]*?```/g, '(code)').replace(/`/g, "'");
message = message.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1').replace(/\[([^\]]{1,100})\]/g, '($1)').replace(/[\[\]]/g, '');
const countChar = (str, ch) => str.split(ch).length - 1;
if (countChar(message, '*') % 2 !== 0) message = message.replace(/\*/g, '');
if (countChar(message, '_') % 2 !== 0) message = message.replace(/_/g, ' ');

try {
  const body = JSON.stringify({ chat_id: Number($env.TELEGRAM_CHAT_ID || ''), text: message, parse_mode: 'Markdown' });
  execSync(`curl -s -X POST -H "Content-Type: application/json" -d '${body.replace(/'/g, "'\\''")}'  "https://api.telegram.org/bot${$env.RESEARCH_BOT_TOKEN || ''}/sendMessage"`, {
    encoding: 'utf-8', timeout: 10000
  });
} catch(e) {}

return [{ json: { sent: true } }];
